{% extends "base.html" %}

{% block title %}Next Actions -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="next-actions">
    <h1>Next Actions</h1>

    {% if let Some(error) = error_message %}
    <div class="next-actions__error" role="alert">{{ error }}</div>
    {% endif %}

    <nav class="next-actions__filters" aria-label="Filter by context">
        <ul class="next-actions__filter-list" role="list">
            <li>
                <a href="/next-actions"{% if selected_context.is_none() %} aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %} class="next-actions__filter-link"{% endif %}>All</a>
            </li>
            {% for ctx in contexts %}
            <li>
                <a href="/next-actions?context={{ ctx.id }}"{% if selected_context.as_deref() == Some(ctx.id.as_str()) %} aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %} class="next-actions__filter-link"{% endif %}>{{ ctx.name }}</a>
            </li>
            {% endfor %}
        </ul>
    </nav>

    {% if !contexts.is_empty() %}
    <form
        method="post"
        action="/next-actions"
        class="next-actions__add"
        hx-post="/next-actions"
        hx-target="#next-actions-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) { this.querySelector('#next-action-title').value = ''; this.querySelector('#next-action-title').focus(); }"
    >
        <label for="next-action-title">Add next action</label>
        <div class="next-actions__add-row">
            <input
                type="text"
                id="next-action-title"
                name="title"
                placeholder="What's the next action?"
                maxlength="300"
                autocomplete="off"
                class="next-actions__add-input"
            >
            <select id="next-action-context" name="context_id" class="next-actions__add-context" aria-label="Context">
                {% for ctx in contexts %}
                <option value="{{ ctx.id }}">{{ ctx.name }}</option>
                {% endfor %}
            </select>
            <button type="submit" class="next-actions__add-submit">Add</button>
        </div>
    </form>
    {% endif %}

    {% if actions.is_empty() %}
    <div class="next-actions__empty-state" id="next-actions-empty-state">
        <p>No next actions yet. Process your <a href="/inbox">inbox</a> to find things to do.</p>
    </div>
    {% endif %}
    <ul class="next-actions__list" role="list" id="next-actions-list"{% if actions.is_empty() %} hidden{% endif %}>
        {% for action in actions %}
        {% include "next_action_item.html" %}
        {% endfor %}
    </ul>
</div>
{% endblock %}

{% block scripts %}
<script>
document.getElementById('next-actions-list').addEventListener('htmx:afterSwap', function() {
    var list = document.getElementById('next-actions-list');
    var emptyState = document.getElementById('next-actions-empty-state');
    if (list && list.children.length > 0) {
        list.hidden = false;
        if (emptyState) emptyState.hidden = true;
    }
});
document.body.addEventListener('htmx:afterSettle', function() {
    var list = document.getElementById('next-actions-list');
    var emptyState = document.getElementById('next-actions-empty-state');
    if (list && list.children.length === 0 && emptyState) {
        list.hidden = true;
        emptyState.hidden = false;
    }
});
</script>
{% endblock %}

use axum::Router;
use sqlx::postgres::PgPoolOptions;
use sqlx::PgPool;
use tokio::net::TcpListener;
use tower_http::request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer};
use tower_http::services::ServeDir;
use tower_http::trace::TraceLayer;
use tower_sessions::SessionManagerLayer;
use tower_sessions_sqlx_store::PostgresStore;

use crate::configuration::Settings;
use crate::routes::{
    get_contexts, get_dashboard, get_edit_context, get_edit_next_action, get_edit_todo,
    get_forgot_password, get_inbox, get_login, get_next_action_item, get_next_actions,
    get_projects, get_register, get_review, get_someday_maybe, get_todo_item, get_todos_page,
    get_waiting_for, health_check, index, post_complete_next_action, post_context,
    post_delete_context, post_delete_inbox_item, post_delete_next_action, post_delete_todo,
    post_edit_context, post_edit_next_action, post_edit_todo, post_inbox, post_login, post_logout,
    post_next_action, post_register, post_todo, post_toggle_todo,
};

pub struct Application {
    listener: TcpListener,
    pool: PgPool,
}

impl Application {
    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
        let pool = PgPoolOptions::new()
            .max_connections(5)
            .connect_with(settings.database.connect_options())
            .await?;

        sqlx::migrate!("./migrations").run(&pool).await?;

        let session_store = PostgresStore::new(pool.clone());
        session_store.migrate().await?;

        let address = format!(
            "{}:{}",
            settings.application.host, settings.application.port
        );
        let listener = TcpListener::bind(&address).await?;

        tracing::info!("Listening on {}", listener.local_addr()?);

        Ok(Self { listener, pool })
    }

    pub fn port(&self) -> u16 {
        self.listener.local_addr().unwrap().port()
    }

    pub fn router(pool: PgPool) -> Router {
        let x_request_id = axum::http::HeaderName::from_static("x-request-id");

        let session_store = PostgresStore::new(pool.clone());
        let session_layer = SessionManagerLayer::new(session_store);

        Router::new()
            .route("/", axum::routing::get(index))
            .route("/dashboard", axum::routing::get(get_dashboard))
            .route("/inbox", axum::routing::get(get_inbox).post(post_inbox))
            .route(
                "/inbox/{id}/delete",
                axum::routing::post(post_delete_inbox_item),
            )
            .route(
                "/contexts",
                axum::routing::get(get_contexts).post(post_context),
            )
            .route(
                "/contexts/{id}/edit",
                axum::routing::get(get_edit_context).post(post_edit_context),
            )
            .route(
                "/contexts/{id}/delete",
                axum::routing::post(post_delete_context),
            )
            .route(
                "/next-actions",
                axum::routing::get(get_next_actions).post(post_next_action),
            )
            .route(
                "/next-actions/{id}",
                axum::routing::get(get_next_action_item),
            )
            .route(
                "/next-actions/{id}/complete",
                axum::routing::post(post_complete_next_action),
            )
            .route(
                "/next-actions/{id}/delete",
                axum::routing::post(post_delete_next_action),
            )
            .route(
                "/next-actions/{id}/edit",
                axum::routing::get(get_edit_next_action).post(post_edit_next_action),
            )
            .route("/projects", axum::routing::get(get_projects))
            .route("/waiting-for", axum::routing::get(get_waiting_for))
            .route("/someday-maybe", axum::routing::get(get_someday_maybe))
            .route("/review", axum::routing::get(get_review))
            .route(
                "/register",
                axum::routing::get(get_register).post(post_register),
            )
            .route("/login", axum::routing::get(get_login).post(post_login))
            .route("/forgot-password", axum::routing::get(get_forgot_password))
            .route("/logout", axum::routing::post(post_logout))
            .route("/todos", axum::routing::get(get_todos_page).post(post_todo))
            .route("/todos/{id}", axum::routing::get(get_todo_item))
            .route("/todos/{id}/toggle", axum::routing::post(post_toggle_todo))
            .route("/todos/{id}/delete", axum::routing::post(post_delete_todo))
            .route(
                "/todos/{id}/edit",
                axum::routing::get(get_edit_todo).post(post_edit_todo),
            )
            .route("/health_check", axum::routing::get(health_check))
            .nest_service("/static", ServeDir::new("static"))
            .layer(session_layer)
            .layer(TraceLayer::new_for_http())
            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
            .with_state(pool)
    }

    pub async fn run(self) -> Result<(), std::io::Error> {
        let router = Self::router(self.pool);
        axum::serve(self.listener, router).await
    }
}

